import java.io.*;

public class SecureDeserializationExample {
    public static void main(String[] args) {
        try {
            byte[] serializedData = // Retrieve serialized data from a trusted source

            ByteArrayInputStream bis = new ByteArrayInputStream(serializedData);
            ObjectInputStream ois = new ObjectInputStream(bis);

            // Perform type checking before deserializing the object
            Object obj = ois.readObject();
            if (obj instanceof MyClass) {
                MyClass myObject = (MyClass) obj;
                // Process the deserialized object
                System.out.println("Deserialized object: " + myObject.toString());
            } else {
                System.out.println("Invalid object type");
            }

            ois.close();
            bis.close();
        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }
}

